import React, { useEffect, useState, useContext } from 'react';
import api from '../api/axiosConfig';
import { AuthContext } from '../context/AuthContext';
import ReactMarkdown from 'react-markdown';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart3, AlignLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  // FIXED: Removed unused 'token' to clear warning
  const { user } = useContext(AuthContext); 
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  const fetchHistory = async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(res.data);
    } catch (err) {
      toast.error("VAULT_SYNC_ERROR");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_WIPE: Proceed with deletion?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("STRATEGY_DELETED");
    } catch (err) { toast.error("WIPE_FAILURE"); }
  };

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Finify_Strategy_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) { toast.error("EXPORT_FAILED"); }
  };

  useEffect(() => { fetchHistory(); }, []);

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div className="reveal-node" style={containerStyle}>
      <div style={headerRow}>
        <h2 style={headerStyle}><Archive size={22} color="var(--accent-primary)"/> STRATEGY_VAULT</h2>
        <div style={vaultBadge}><BarChart3 size={12} /> {history.length} NODES_STORED</div>
      </div>
      
      <div style={listStyle}>
        {history.map((item) => (
          <div key={item.id} className="vault-card" style={cardStyle}>
            <div style={cardMeta}>
              <div style={{ display: 'flex', gap: '15px' }}>
                <span style={dateTag}><Calendar size={11}/> {new Date(item.created_at).toLocaleDateString()}</span>
                <span style={riskTag}><ShieldCheck size={11}/> RISK: {item.risk_score}</span>
              </div>
              <div style={cardActions}>
                <button onClick={() => setSelectedItem(item)} style={iconBtn} title="Full Description"><Eye size={17}/></button>
                <button onClick={() => handleDownload(item)} style={iconBtn} title="Export PDF"><Download size={17}/></button>
                <button onClick={() => handleDelete(item.id)} style={deleteBtn} title="Wipe"><Trash2 size={17}/></button>
              </div>
            </div>

            <h4 style={titleStyle}>{item.goal}</h4>

            <div style={sectionBlock}>
              <p style={labelSmall}><AlignLeft size={10} style={{marginRight:'6px'}}/> MARKET_SUMMARY</p>
              <div className="markdown-vault">
                <ReactMarkdown>{item.summary}</ReactMarkdown>
              </div>
            </div>
          </div>
        ))}
      </div>

      {selectedItem && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <span style={modalId}>NODE_DATA // ID_{selectedItem.id}</span>
              <button onClick={() => setSelectedItem(null)} style={closeBtn}><X size={20}/></button>
            </div>
            <div style={modalBody}>
              <h3 style={modalTitle}>{selectedItem.goal}</h3>
              <div style={modalSection}>
                <p style={modalLabel}><AlignLeft size={10} style={{marginRight:'8px'}}/> AGENTIC_RATIONALE</p>
                <div className="markdown-vault">
                    <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .markdown-vault h1, .markdown-vault h2 { color: var(--accent-primary); font-size: 0.95rem; margin-top: 1.5rem; text-transform: uppercase; }
        .markdown-vault p { color: var(--text-secondary); font-size: 0.9rem; line-height: 1.8; margin-bottom: 1rem; }
        .vault-card:hover { border-color: var(--accent-primary) !important; transform: translateY(-3px); }
        .reveal-node { animation: fadeIn 0.4s ease; }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
      `}</style>
    </div>
  );
};

/* --- Terminal Styles --- */
const containerStyle = { padding: '3rem 2rem', maxWidth: '1000px', margin: '0 auto' };
const headerRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '3rem', borderBottom: '1px solid var(--surface-border)', paddingBottom: '1.5rem' };
const headerStyle = { display: 'flex', alignItems: 'center', gap: '12px', fontSize: '1.3rem', fontWeight: 900, color: 'var(--text-primary)', margin: 0 };
const vaultBadge = { fontSize: '0.6rem', color: 'var(--accent-primary)', fontWeight: 800, background: 'rgba(16,185,129,0.08)', padding: '6px 12px', borderRadius: '4px', border: '1px solid var(--accent-muted)', display: 'flex', alignItems: 'center', gap: '8px' };
const listStyle = { display: 'flex', flexDirection: 'column', gap: '1.5rem' };
const cardStyle = { padding: '2rem', background: 'var(--surface-glass)', border: '1px solid var(--surface-border)', borderRadius: '24px', transition: 'all 0.3s ease' };
const cardMeta = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' };
const dateTag = { fontSize: '0.65rem', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: '5px', fontWeight: 700 };
const riskTag = { fontSize: '0.65rem', color: 'var(--accent-primary)', fontWeight: 900, display: 'flex', alignItems: 'center', gap: '5px' };
const titleStyle = { fontSize: '1.2rem', fontWeight: 900, color: 'var(--text-primary)', margin: '0 0 1.5rem 0' };
const sectionBlock = { padding: '0 0.5rem' };
const labelSmall = { fontSize: '0.55rem', fontWeight: 900, color: 'var(--text-muted)', letterSpacing: '0.2em', marginBottom: '1rem', display: 'flex', alignItems: 'center' };
const cardActions = { display: 'flex', gap: '10px' };
const iconBtn = { background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', padding: '6px', borderRadius: '8px' };
const deleteBtn = { ...iconBtn, color: '#ef4444' };
const modalOverlay = { position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(5, 5, 5, 0.94)', backdropFilter: 'blur(12px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 3000 };
const modalContent = { width: '92%', maxWidth: '800px', background: '#0d0f14', border: '1px solid var(--accent-primary)', borderRadius: '28px', overflow: 'hidden' };
